/**
 * Writes src/superdry-client-embedded.js from src/superdry-client.js so Workers can
 * serve the browser bundle via Response() without filesystem reads at runtime.
 */
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");
const sourcePath = join(root, "src", "superdry-client.js");
const outPath = join(root, "src", "superdry-client-embedded.js");

const src = readFileSync(sourcePath, "utf8");
const banner =
  "/* Generated by scripts/embed-superdry-client.mjs — edit superdry-client.js and re-run: node scripts/embed-superdry-client.mjs */\n";
const body = `${banner}export const SUPERDRY_CLIENT_SOURCE = ${JSON.stringify(src)};\n`;

writeFileSync(outPath, body, "utf8");
console.error("wrote", outPath);
